// Download attachment and save to temp folder
const items = $input.all();
const fs = require('fs');
const path = require('path');

const results = [];
for (const item of items) {
  const attachment = item.json.attachments?.[0];
  if (!attachment) continue;

  const tmpDir = '/tmp/n8n-invoices';
  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });

  const filePath = path.join(tmpDir, `${Date.now()}_${attachment.filename}`);
  const buffer = Buffer.from(attachment.data, 'base64');
  fs.writeFileSync(filePath, buffer);

  results.push({
    json: {
      file_path: filePath,
      source_email: item.json.from,
      subject: item.json.subject,
      filename: attachment.filename
    }
  });
}
return results;

// Parse SOL response
const response = $input.first().json;
if (response.status === 'success') {
  return [{
    json: {
      invoice_id: response.invoice_id,
      vendor_name: response.extracted_data.vendor_name,
      invoice_number: response.extracted_data.invoice_number,
      invoice_date: response.extracted_data.invoice_date,
      total_amount: response.extracted_data.total_amount,
      line_items: JSON.stringify(response.extracted_data.line_items),
      source_email: response.source_email,
      extraction_method: response.extraction_method
    }
  }];
} else {
  throw new Error(`Extraction failed: ${response.message}`);
}
